import{_ as e}from"./chunks/dashboard.B0ClCvQC.js";import{_ as a,o as r,c as i,a2 as o}from"./chunks/framework.BflysNKA.js";const d="/images/registration-flow.svg",m=JSON.parse('{"title":"欢迎使用 小蓝中转站","description":"","frontmatter":{},"headers":[],"relativePath":"intro/welcome.md","filePath":"intro/welcome.md","lastUpdated":1778577020000}'),l={name:"intro/welcome.md"};function n(s,t,h,p,c,u){return r(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="欢迎使用-xiaolan-ai" tabindex="-1">欢迎使用 小蓝中转站 <a class="header-anchor" href="#欢迎使用-xiaolan-ai" aria-label="Permalink to &quot;欢迎使用 小蓝中转站&quot;">​</a></h1><p>小蓝中转站 是专为开发者打造的<strong>统一 AI 编程模型网关</strong>。在这里，你不再需要为网络连通性、跨国支付壁垒和繁琐的多平台账号管理而头疼。</p><p>一个入口，一个账号，统一管理模型、Key、账单和常用开发工具接入。</p><p>如果你刚开始接触 Claude Code、Codex 或 Cherry Studio，先从“新手上路”开始；如果已经熟悉 OpenAI 兼容接口，直接复制 Endpoint、Key 和模型名即可接入。</p><p><img src="'+d+'" alt="注册到首次请求流程"></p><h2 id="为什么是-xiaolan-ai" tabindex="-1">为什么是 小蓝中转站？ <a class="header-anchor" href="#为什么是-xiaolan-ai" aria-label="Permalink to &quot;为什么是 小蓝中转站？&quot;">​</a></h2><h3 id="🔌-统一接口接入" tabindex="-1">🔌 统一接口接入 <a class="header-anchor" href="#🔌-统一接口接入" aria-label="Permalink to &quot;🔌 统一接口接入&quot;">​</a></h3><p>在支持 OpenAI 兼容接口的工具中填入 <code>https://xiaolan1.cn/v1</code> 和你的专属 Key，即可通过统一网关调用可用模型。</p><p>但第一次接入时，最好再多记一句：<br> 不是所有工具都直接填 <code>https://xiaolan1.cn/v1</code>。Claude Code、Gemini CLI、Cherry Studio 这类工具还有各自的地址口径，文档里都已经单独拆开说明。</p><h3 id="💳-人民币余额与账单" tabindex="-1">💳 人民币余额与账单 <a class="header-anchor" href="#💳-人民币余额与账单" aria-label="Permalink to &quot;💳 人民币余额与账单&quot;">​</a></h3><p>站内余额和消费记录按人民币展示。模型价格与倍率在<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>查看，充值和请求明细在控制台查看。</p><h3 id="🛠️-开发者工具优先" tabindex="-1">🛠️ 开发者工具优先 <a class="header-anchor" href="#🛠️-开发者工具优先" aria-label="Permalink to &quot;🛠️ 开发者工具优先&quot;">​</a></h3><p>文档覆盖 Claude Code、Codex、Gemini CLI、Cherry Studio 等常用工具，包含下载入口、基础环境、配置项和最小验证步骤。</p><h3 id="🔐-聚合且安全的凭证中心" tabindex="-1">🔐 聚合且安全的凭证中心 <a class="header-anchor" href="#🔐-聚合且安全的凭证中心" aria-label="Permalink to &quot;🔐 聚合且安全的凭证中心&quot;">​</a></h3><p>在 小蓝中转站 控制台可以按设备、工具或项目创建独立 Key，配置额度、权限和启用状态，便于定位消耗和处理泄露。</p><h2 id="先看懂四个最常用的概念" tabindex="-1">先看懂四个最常用的概念 <a class="header-anchor" href="#先看懂四个最常用的概念" aria-label="Permalink to &quot;先看懂四个最常用的概念&quot;">​</a></h2><p>第一次接入时，最容易混淆的不是某个命令，而是这四件事到底各自负责什么：</p><table tabindex="0"><thead><tr><th>概念</th><th>作用</th><th>用在哪里</th></tr></thead><tbody><tr><td>账号</td><td>登录控制台、查看余额、日志和订单</td><td>官网控制台</td></tr><tr><td>余额</td><td>支付模型请求费用</td><td>钱包 / 账单</td></tr><tr><td>Key</td><td>客户端调用网关时的凭证</td><td>CLI、桌面客户端、脚本</td></tr><tr><td>模型</td><td>实际请求的目标模型</td><td><code>model</code> 字段</td></tr></tbody></table><p>登录控制台后，你会看到这样的界面：</p><p><img src="'+e+'" alt="控制台概览 — 余额统计、公告、FAQ、API 信息和运行状态"></p><p>它们的关系可以简单理解成：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>账号负责管理 -&gt; 余额保证可用 -&gt; Key 负责鉴权 -&gt; 模型决定具体调用谁</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>只要其中一项没准备好，客户端就可能报错。所以第一次接入时，先把顺序走通，比一开始就换模型、换工具更重要。</p><h2 id="推荐接入顺序" tabindex="-1">推荐接入顺序 <a class="header-anchor" href="#推荐接入顺序" aria-label="Permalink to &quot;推荐接入顺序&quot;">​</a></h2><p>第一次配置时按此顺序完成。每一步都对应一个常见卡点：本地命令、账号、Key、模型名和工具配置。</p><ol><li>🧭 <strong><a href="/beginner/windows">Windows 快速接入</a></strong> / <strong><a href="/beginner/macos">macOS 快速接入</a></strong>：完成本地环境和 CLI 配置。</li><li>🏁 <strong><a href="/guide/registration">注册账号</a></strong>：登录控制台。</li><li>🔑 <strong><a href="/guide/create-key">创建专属 Key</a></strong>：生成工具调用凭证。</li><li>🚀 <strong><a href="/deploy/claude-code">配置编程工具</a></strong>：以 Claude Code 为例，也可以直接选择左侧对应工具。</li></ol><p>第一次最容易卡住的，不是哪一个命令，而是顺序乱了：</p><ul><li>还没充值，就先怀疑模型名错了</li><li>还没建 Key，就先怀疑工具安装坏了</li><li>还没分清根地址和 <code>/v1</code>，就先到处改环境变量</li></ul><p>按这四步顺着走，通常能少掉很多反复回退。</p><h2 id="第一次接入怎么选工具" tabindex="-1">第一次接入怎么选工具 <a class="header-anchor" href="#第一次接入怎么选工具" aria-label="Permalink to &quot;第一次接入怎么选工具&quot;">​</a></h2><p>不需要把所有工具都装一遍。先选一条最贴近当前目标的路径，通常最容易一次跑通。</p><table tabindex="0"><thead><tr><th>你现在要做什么</th><th>建议先用什么</th><th>原因</th></tr></thead><tbody><tr><td>先确认接口是否可用</td><td>Cherry Studio</td><td>图形界面最直观，先验证地址、Key 和模型</td></tr><tr><td>想直接在项目目录里改代码</td><td>Claude Code</td><td>终端工作流最直接</td></tr><tr><td>已经熟悉 OpenAI CLI 风格</td><td>Codex</td><td>配置方式更接近 OpenAI 兼容用法</td></tr><tr><td>想做长文总结或大仓库理解</td><td>Gemini CLI</td><td>更常见于长上下文场景</td></tr></tbody></table><p>一旦先跑通其中一个工具，后面再配置第二个工具时，就能把问题范围缩小到“工具差异”，而不是从头怀疑账号、Key、余额和模型。</p><p>真正算“第一条链路跑通”时，通常要同时满足：</p><ol><li>工具能正常启动</li><li>发一句短消息后能正常返回</li><li>控制台日志里能看到对应请求</li><li>你知道当前这条请求用的是哪一把 Key、哪个模型</li></ol><h2 id="常用传送门" tabindex="-1">常用传送门 <a class="header-anchor" href="#常用传送门" aria-label="Permalink to &quot;常用传送门&quot;">​</a></h2><ul><li><strong>全局 Endpoint</strong>: <code>https://xiaolan1.cn/v1</code></li><li><strong>控制台主站</strong>: <a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">https://xiaolan1.cn</a></li><li><strong>模型费率广场</strong>: <a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">https://xiaolan1.cn/pricing</a></li><li><strong>Windows 接入</strong>: <a href="/beginner/windows">Windows 快速接入</a></li><li><strong>macOS 接入</strong>: <a href="/beginner/macos">macOS 快速接入</a></li></ul><h2 id="进阶探索" tabindex="-1">进阶探索 <a class="header-anchor" href="#进阶探索" aria-label="Permalink to &quot;进阶探索&quot;">​</a></h2><ul><li><a href="/intro/overview">了解网关的运作原理</a></li><li><a href="/apps/cherry-studio">浏览更多支持的第三方客户端</a></li><li><a href="/support/troubleshooting">查看排障手册</a></li></ul>',39)])])}const f=a(l,[["render",n]]);export{m as __pageData,f as default};
